const d = $json;

if (!d.session_id || typeof d.session_id !== 'string') {
  throw new Error('session_id requerido');
}
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!UUID_RE.test(d.session_id)) {
  throw new Error('session_id debe ser UUID valido');
}

const MOTIVO_ENUM = new Set(['lead_solicito', 'bot_no_pudo_resolver', 'score_alto_proactivo']);
const motivo = MOTIVO_ENUM.has(d.motivo) ? d.motivo : 'lead_solicito';

const clean = (v, max) => (v === undefined || v === null) ? '' : v.toString().trim().slice(0, max);

return [{ json: {
  session_id: d.session_id,
  motivo,
  nombre_agent: clean(d.nombre, 120),
  email_agent: clean(d.email, 200),
  whatsapp_agent: clean(d.whatsapp, 40),
  resumen_agent: clean(d.resumen, 1200),
  contexto: clean(d.contexto, 500),
} }];

const input = $('Validate Input').first().json;
const raw = $json;

// n8n HTTP Request auto-unwraps Supabase single-row arrays into objects.
// Accept both shapes: array with rows, or direct object with id.
let lead = null;
if (Array.isArray(raw) && raw.length > 0) {
  lead = raw[0];
} else if (raw && typeof raw === 'object' && raw.id) {
  lead = raw;
}

if (!lead) {
  return [{ json: {
    ok: false,
    reason: 'lead_no_existe',
    session_id: input.session_id,
    skip_patch: true,
    skip_notif: true,
    patchBody: {},
    notifPayload: { skip_send: true },
    nombre: input.nombre_agent || '',
    lead_id: null,
    tool_output_text: 'No encontre tu registro de sesion. Por favor escribeme tu nombre, WhatsApp y correo para pasarle tus datos al equipo.',
  } }];
}

// Agent-provided values override DB values (agent has fresh context from the conversation).
const nombre = input.nombre_agent || lead.nombre || '';
const email = input.email_agent || lead.email || '';
const whatsapp = input.whatsapp_agent || lead.whatsapp || '';
const resumen = input.resumen_agent || lead.resumen || '';

const prevHistory = Array.isArray(lead.score_history) ? lead.score_history : [];
const prevScoreNumeric = typeof lead.score_numeric === 'number' ? lead.score_numeric : 0;
const newScoreNumeric = Math.max(prevScoreNumeric, 75);

const historyEntry = {
  at: new Date().toISOString(),
  action: 'broker_requested',
  motivo: input.motivo,
  contexto: input.contexto,
  score_numeric_before: prevScoreNumeric,
  score_numeric_after: newScoreNumeric,
};

const patchBody = {
  broker_requested_at: new Date().toISOString(),
  broker_request_reason: input.motivo,
  score: 'CALIENTE',
  score_numeric: newScoreNumeric,
  score_history: [...prevHistory, historyEntry],
  // Si el agente refrescó datos de contacto o resumen, los persistimos.
  ...(input.nombre_agent ? { nombre } : {}),
  ...(input.email_agent ? { email } : {}),
  ...(input.whatsapp_agent ? { whatsapp } : {}),
  ...(input.resumen_agent ? { resumen } : {}),
};

const notifPayload = {
  lead_id: lead.id,
  session_id: input.session_id,
  nombre,
  whatsapp,
  email,
  resumen,
  motivo: input.motivo,
  contexto: input.contexto,
  broker_request: true,
};

return [{ json: {
  ok: true,
  session_id: input.session_id,
  lead_id: lead.id,
  patchBody,
  notifPayload,
  nombre,
  skip_patch: false,
  skip_notif: false,
} }];

const prepared = $('Build payloads').first().json;
const notif = $json;

if (prepared.ok === false) {
  return [{ json: {
    ok: false,
    reason: prepared.reason,
    session_id: prepared.session_id,
    tool_output_text: prepared.tool_output_text,
  } }];
}

const primerNombre = (prepared.nombre || '').split(' ')[0] || 'hola';

return [{ json: {
  ok: true,
  lead_id: prepared.lead_id,
  session_id: prepared.session_id,
  broker_notificado: !!(notif && notif.notified),
  tool_output_text: `Listo ${primerNombre}, le paso tu solicitud al equipo. Te van a contactar por WhatsApp en horario lun-vie 9-19 hrs. Si es urgente, tambien podes escribir al +56 9 4032 9987.`,
} }];
